export function getScorers(year: number, teamA: string, teamB: string): [string[], string[]] | null {
  const [a, b] = [teamA, teamB].sort();
  const key = `${year}_${a}_${b}`;
  const v = SCORERS[key];
  if (!v) return null;
  return teamA === a ? v : [v[1], v[0]];
}
